    public object Id { get; set; }

    public class DeleteWishListCommandHandler : IRequestHandler<DeleteWishListCommand,(object id, Status status)>
    {
        private readonly IPoseidonDbContext _context;
        private readonly ILogger<DeleteWishListCommandHandler> _logger;
        
        public DeleteWishListCommandHandler(IPoseidonDbContext context 
                                                 , ILogger<DeleteWishListCommandHandler> logger)
        {
            _context = context;
           _logger   = logger ;
        }

        public async Task<(object, Status)> Handle(DeleteWishListCommand request, CancellationToken cancellationToken)
        {
            var entity = await _context.WishList
                                       .FindAsync(request.Id);

            if (entity is null)
            { 
                _logger.Warning(string.Format("Not found  WishList {0}", request.Id));
                return (request.Id, Status.NotFound);
            }

            _context.WishList.Remove(entity);

            await _context.SaveChangesAsync(cancellationToken);

            _logger.Info(string.Format("Deleted  WishList {0}", request.Id)); 

            return (request.Id, Status.Deleted);
        }
    }
}

