public partial class UpsertWishListItemCommandHandler : IRequestHandler<WishListItemCommand, (object id, Status status)>
{
    private readonly IPoseidonDbContext _context;
    private readonly ILogger<UpsertWishListItemCommandHandler> _logger ;
    public UpsertWishListItemCommandHandler( IPoseidonDbContext context 
                                            , ILogger<UpsertWishListItemCommandHandler> logger
                                            )
    {
        _context = context; 
        _logger  = logger ;
    }

    public async Task<(object id, Status status)> Handle(WishListItemCommand request, CancellationToken cancellationToken)
    {
        WishListItem? entity = null;
        Status         status;
        if(request.WishListItemId.HasValue)
        {
             entity = await _context.WishListItem.FindAsync(request.WishListItemId.Value);
        }

        if (entity is not null)
        {
            entity.WishListItemId = request.WishListItemId!.Value;
            status                 = Status.Updated;
        }
        else
        {
             entity = new WishListItem();
            _context.WishListItem.Add(entity);
             status = Status.Created;
        } 
          


        if(request.Note            != null) entity.Note            = request.Note!.Value                ;
        if(request.Quantity        != null) entity.Quantity        = request.Quantity!.Value            ;
        if(request.WishListId      != null) entity.WishListId      = request.WishListId!.Value          ;
        if(request.ProductId       != null) entity.ProductId       = request.ProductId!.Value           ;

         await _context.SaveChangesAsync(cancellationToken);
        
        if(status is Status.Created)
        {
             _logger.Info(string.Format("Created  WishListItem {0}", entity.WishListItemId));
        }else
        {
             _logger.Info(string.Format("Updated  WishListItem {0}", entity.WishListItemId)); 
        } 

        return (entity.WishListItemId ,status);
    }

    partial void WishListItemPostOperation();
}


public partial class GetWishListItemCommandHandler : IRequestHandler<WishListItemQuery, ResponseData<WishListItemDto>>
{
    private readonly IPoseidonDbContext _context;
    private readonly IMapper            _mapper;
    private readonly ILogger<GetWishListItemCommandHandler> _logger;

    public GetWishListItemCommandHandler(IPoseidonDbContext context
                                             , IMapper mapper
                                             , ILogger<GetWishListItemCommandHandler> logger)
    {
        _context = context;
        _mapper  = mapper ;
        _logger  = logger ;
    }

    public async Task<ResponseData<WishListItemDto>> Handle(WishListItemQuery request, CancellationToken cancellationToken)
    { 
        _logger.Info(string.Format("Getting WishListItem page number {0} page size {1} orderby {2} filter {3}", request.Page, request.PageSize, request.OrderBy, request.Filter));
        
        var (count, query) = await _context.WishListItem
                            .AsNoTracking()
                            .ProjectTo<WishListItemDto>(_mapper.ConfigurationProvider)
                            .GridifyQueryableAsync(request, null); 

        return await query.ResponseDataAsync(count, request.Page, request.PageSize);
       
    }
}



